// Payload de Stripe webhook o CRM
const body = $input.first().json.body || $input.first().json;

// Stripe: body.data.object o body directo desde CRM
const stripeObj    = body.data?.object || body;
const customerName = stripeObj.metadata?.customer_name || stripeObj.client_name   || stripeObj.nombre    || 'Cliente';
const agentName    = stripeObj.metadata?.agent_name    || stripeObj.agent_name    || stripeObj.asesor    || 'Sin asignar';
const amountRaw    = stripeObj.amount_received          || stripeObj.amount         || stripeObj.monto     || 0;
const currency     = (stripeObj.currency || 'usd').toUpperCase();
const description  = stripeObj.description              || stripeObj.concepto       || stripeObj.plan      || '';
const paymentId    = stripeObj.id || stripeObj.payment_id || '';

// Convertir centavos a dólares si viene de Stripe
const amount = currency === 'USD' && amountRaw > 1000 ? (amountRaw / 100).toFixed(2) : amountRaw;

const now = new Date();
const hora = now.toLocaleTimeString('es-CO', { hour: '2-digit', minute: '2-digit', timeZone: 'America/Bogota' });
const fecha = now.toLocaleDateString('es-CO', { day: '2-digit', month: '2-digit', year: 'numeric', timeZone: 'America/Bogota' });

const message = [
  '💰 *PAGO RECIBIDO - GO EASY CRM*',
  '',
  `👤 *Cliente:* ${customerName}`,
  `💵 *Monto:* $${amount} ${currency}`,
  description ? `📋 *Concepto:* ${description}` : null,
  `🧑‍💼 *Asesor:* ${agentName}`,
  `📅 *Fecha:* ${fecha} ${hora} (Col)`,
  paymentId ? `🆔 *Ref:* ${paymentId.slice(-8)}` : null,
  '',
  '✅ _Pago confirmado exitosamente_ 🎉',
].filter(Boolean).join('\n');

return [{ json: { message, amount, currency, customerName } }];
